class User extends Authenticatable
{
    use HasFactory, SoftDeletes, HasUlids;

    protected $fillable = ['name', 'email', 'password'];
    protected $hidden = ['password', 'remember_token'];
    protected $casts = [
        'email_verified_at' => 'datetime',
        'settings' => 'array',
        'is_active' => 'boolean',
    ];
    protected $with = [];  // never declare relations here

    public function orders(): HasMany
    {
        return $this->hasMany(Order::class);
    }

    public function scopeActive(Builder $q): Builder
    {
        return $q->where('is_active', true);
    }

    public function scopeSearch(Builder $q, ?string $term): Builder
    {
        if (empty($term)) return $q;
        return $q->where(fn($inner) =>
            $inner->where('name', 'LIKE', "%{$term}%")
                  ->orWhere('email', 'LIKE', "%{$term}%")
        );
    }

    protected function email(): Attribute
    {
        return Attribute::make(set: fn(string $v) => strtolower($v));
    }
}

class UsersQuery
{
    public function __construct(private Builder $query) {}

    public static function make(): self
    {
        return new self(User::query());
    }

    public function active(): self
    {
        $this->query->where('is_active', true);
        return $this;
    }

    public function search(?string $term): self
    {
        if (filled($term)) {
            $this->query->whereAny(['name', 'email'], 'LIKE', "%$term%");
        }
        return $this;
    }

    public function paginate(int $per = 20): LengthAwarePaginator
    {
        return $this->query->with('roles')->latest()->paginate($per);
    }
}

// Usage in controller/service:
// UsersQuery::make()->active()->search($request->search)->paginate(20)
